#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifdef ENABLE_DP
#define HAS_DOUBLE 1
#else
#define HAS_DOUBLE 0
#endif

#ifdef ENABLE_HP
#define HAS_HALF 1
#else
#define HAS_HALF 0
#endif

#ifdef BLOCK_STRIDED
#define BLOCK_STRIDED_MODE 1
#else
#define BLOCK_STRIDED_MODE 0
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 0
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifdef class_T
typedef class_T T;
#else
typedef float T;
#endif

#ifdef ENABLE_HP
typedef struct {
    half x;
    half y;
} half2;
#endif

inline T my_conv_int(int i) {
    return (T)i;
}

inline T my_mad(T a, T b, T c) {
    return a * b + c;
}

inline int my_equal(T a, T b) {
    return a == b;
}

#ifdef ENABLE_HP
inline half2 my_conv_int_half2(int i) {
    half h = (half)i;
    half2 res;
    res.x = h;
    res.y = h;
    return res;
}

inline half2 my_mad_half2(half2 a, half2 b, half2 c) {
    half2 res;
    res.x = a.x * b.x + c.x;
    res.y = a.y * b.y + c.y;
    return res;
}

inline int my_equal_half2(half2 a, half2 b) {
    return (a.x == b.x) && (a.y == b.y);
}
#endif

__kernel void benchmark_func(T seed, __global T *g_data) {
    const unsigned int blockSize = blockdim;
    const int stride = blockSize;

    int idx;
    if (BLOCK_STRIDED_MODE) {
        idx = get_group_id(0) * blockSize * ELEMENTS_PER_THREAD + get_local_id(0);
    } else {
        idx = get_global_id(0) * ELEMENTS_PER_THREAD;
    }

    const int big_stride = get_num_groups(0) * blockSize * ELEMENTS_PER_THREAD;

    T tmps[ELEMENTS_PER_THREAD];

    for (int k = 0; k < FUSION_DEGREE; k++) {
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            int access_idx = idx + j * stride + k * big_stride;
            if (access_idx < get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE) {
                tmps[j] = g_data[access_idx];

                for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                    tmps[j] = my_mad(tmps[j], tmps[j], seed);
                }
            } else {
                tmps[j] = my_conv_int(0);
            }
        }

        T sum = my_conv_int(0);
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
            sum = my_mad(tmps[j], tmps[j+1], sum);
        }

        if (my_equal(sum, my_conv_int(-1))) {
            int write_idx = idx + k * big_stride;
            if (write_idx < get_global_size(0) * ELEMENTS_PER_THREAD * FUSION_DEGREE) {
                g_data[write_idx] = sum;
            }
        }
    }
}

